from jinja2 import Environment

class MyTrans:
    def gettext(self, s):
        return 'DEFAULT:' + s
    def ngettext(self, s, p, n):
        return 'DEFAULT:' + (s if n==1 else p)
    def dgettext(self, d, s):
        return f'{d}:{s}'
    def dngettext(self, d, s, p, n):
        return f'{d}:' + (s if n==1 else p)

env = Environment(extensions=['jinja2.ext.i18n'])
env.install_gettext_translations(MyTrans(), newstyle=True)
t = env.from_string('{% trans domain=\"admin\", name=\"World\" %}Hello {{ name }}{% endtrans %}')
print(repr(t.render()))
t2 = env.from_string('{% trans count=3, domain=\"shop\" %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(repr(t2.render()))

# fallback newstyle: translations without dgettext
